const btn = document.querySelector<HTMLButtonElement>('#submit')!;

// Register a listener
btn.addEventListener('click', (event: MouseEvent) => {
  console.log('Clicked at', event.clientX, event.clientY);
});

// Named function -- required if you plan to remove the listener later
function handleClick(e: MouseEvent) {
  console.log('Clicked:', e.target);
}
btn.addEventListener('click', handleClick);

// Remove the exact listener (same function reference required)
btn.removeEventListener('click', handleClick);

// Options object
btn.addEventListener('click', handleClick, {
  once:    true,    // auto-removes after first fire
  passive: true,    // hints that preventDefault() won't be called (scroll perf)
  capture: false,   // default: bubble phase (true = capture phase)
});

// MouseEvent extras
document.addEventListener('mousemove', (e: MouseEvent) => {
  console.log(e.clientX, e.clientY); // viewport coords
  console.log(e.pageX,   e.pageY);   // document coords (includes scroll)
  console.log(e.shiftKey, e.ctrlKey, e.altKey, e.metaKey);
  console.log(e.button);  // 0=left, 1=middle, 2=right
});

// KeyboardEvent extras
document.addEventListener('keydown', (e: KeyboardEvent) => {
  console.log(e.key);      // 'Enter', 'ArrowUp', 'a', ...
  console.log(e.code);     // 'KeyA', 'ArrowUp', 'Enter' -- physical key
  console.log(e.repeat);   // true while key is held
  if (e.key === 'Escape') e.preventDefault();
});

// Capture phase: add true as the third argument
document.addEventListener('click', (e) => {
  console.log('CAPTURE on document');
}, true);

// Bubble phase (default)
document.addEventListener('click', (e) => {
  console.log('BUBBLE on document');
});

// Clicking a nested button fires:
// 1. CAPTURE on document
// 2. (capture listeners on body, section, button)
// 3. bubble listeners on button (target phase)
// 4. BUBBLE on document

const inner = document.querySelector('.inner')!;
const outer = document.querySelector('.outer')!;

inner.addEventListener('click', (e) => {
  e.stopPropagation(); // prevents outer from receiving this event
  console.log('inner clicked');
});

outer.addEventListener('click', () => {
  console.log('outer clicked'); // NOT reached after stopPropagation
});

// stopImmediatePropagation also prevents other listeners on the SAME element:
inner.addEventListener('click', (e) => {
  e.stopImmediatePropagation();
});
inner.addEventListener('click', () => {
  // This second listener on inner is also suppressed
  console.log('never runs');
});

const ul = document.querySelector<HTMLUListElement>('ul.todo-list')!;

// One listener handles clicks on ALL current and future <li> items
ul.addEventListener('click', (e: MouseEvent) => {
  const li = (e.target as Element).closest('li');
  if (!li) return; // click was not on or inside an <li>

  const id = li.dataset.id;
  if ((e.target as Element).matches('.delete-btn')) {
    li.remove();
  } else if ((e.target as Element).matches('.complete-btn')) {
    li.classList.toggle('complete');
  }
  console.log('Acting on item', id);
});

// Adding new items later -- the single listener handles them automatically
const newLi = document.createElement('li');
newLi.dataset.id = '42';
newLi.innerHTML = '<span>New task</span><button class="delete-btn">X</button>';
ul.append(newLi);

// Prevent form submission (handle it in JavaScript instead)
const form = document.querySelector<HTMLFormElement>('form')!;
form.addEventListener('submit', (e: SubmitEvent) => {
  e.preventDefault();
  const data = new FormData(form);
  // Process data via fetch...
});

// Prevent link navigation
document.querySelector('a.modal-trigger')!.addEventListener('click', (e) => {
  e.preventDefault();
  openModal();
});

// Prevent right-click context menu on a canvas
const canvas = document.querySelector('canvas')!;
canvas.addEventListener('contextmenu', (e) => e.preventDefault());

// Controlled keyboard shortcut override
document.addEventListener('keydown', (e: KeyboardEvent) => {
  if ((e.ctrlKey || e.metaKey) && e.key === 's') {
    e.preventDefault(); // stop browser Save As dialog
    saveDocument();
  }
});

// Dispatch a custom event
const btn = document.querySelector('#save-btn')!;
btn.dispatchEvent(new CustomEvent('document:save', {
  bubbles:    true,      // allow ancestors to listen
  cancelable: true,
  detail: { userId: 42, content: 'Hello' }, // arbitrary payload
}));

// Listen from a parent element
document.addEventListener('document:save', (e: Event) => {
  const ce = e as CustomEvent<{ userId: number; content: string }>;
  console.log('Saving for user', ce.detail.userId);
});

// Creating a reusable event factory
function saveEvent(detail: { userId: number; content: string }) {
  return new CustomEvent('document:save', { bubbles: true, cancelable: true, detail });
}

@Component({
  selector: 'app-form',
  template: `
    <form (submit)="onSubmit($event)">
      <input
        type="text"
        (input)="onInput($event)"
        (keydown.enter)="onEnter()"
        (keydown.escape)="onEscape()"
      />
      <button type="button" (click)="$event.stopPropagation(); onClick()">Save</button>
    </form>
  `,
})
export class FormComponent {
  onSubmit(e: SubmitEvent) {
    e.preventDefault();
    // handle submission
  }

  onInput(e: Event) {
    const value = (e.target as HTMLInputElement).value;
  }

  onEnter() { /* submit */ }
  onEscape() { /* cancel */ }
  onClick()  { /* save */ }
}

import { Directive, HostListener } from '@angular/core';

@Directive({ selector: '[appClickOutside]' })
export class ClickOutsideDirective {
  @HostListener('document:click', ['$event'])
  onDocumentClick(e: MouseEvent): void {
    // e.target is checked against the host element in the component
    console.log('Document clicked:', e.target);
  }

  @HostListener('keydown.escape')
  onEscape(): void {
    console.log('Escape pressed');
  }
}

import { Component, OnInit, OnDestroy } from '@angular/core';

@Component({ selector: 'app-tracker', template: '' })
export class TrackerComponent implements OnInit, OnDestroy {
  private handleScroll = () => {
    console.log('scrolled to', window.scrollY);
  };

  ngOnInit(): void {
    // Listener registered outside Angular's template: must be manually cleaned up
    window.addEventListener('scroll', this.handleScroll, { passive: true });
  }

  ngOnDestroy(): void {
    window.removeEventListener('scroll', this.handleScroll);
  }
}

// Plain debounce without a library
function debounce<T extends (...args: any[]) => void>(fn: T, ms: number): T {
  let timer: ReturnType<typeof setTimeout>;
  return function(this: unknown, ...args: Parameters<T>) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), ms);
  } as T;
}

const searchInput = document.querySelector<HTMLInputElement>('#search')!;
const fetchResults = debounce((query: string) => {
  console.log('Fetching:', query); // runs 300ms after user stops typing
}, 300);

searchInput.addEventListener('input', (e) => {
  fetchResults((e.target as HTMLInputElement).value);
});

// Plain throttle
function throttle<T extends (...args: any[]) => void>(fn: T, ms: number): T {
  let last = 0;
  return function(this: unknown, ...args: Parameters<T>) {
    const now = Date.now();
    if (now - last >= ms) {
      last = now;
      fn.apply(this, args);
    }
  } as T;
}

const logScroll = throttle(() => {
  console.log('scrollY:', window.scrollY); // at most once every 100ms
}, 100);

window.addEventListener('scroll', logScroll, { passive: true });

const canvas = document.querySelector<HTMLCanvasElement>('canvas')!;

canvas.addEventListener('pointerdown', (e: PointerEvent) => {
  console.log(e.pointerType); // 'mouse' | 'touch' | 'pen'
  console.log(e.pointerId);   // unique ID per contact point (multi-touch)
  console.log(e.pressure);    // 0.0 - 1.0 (pen/touch pressure)
  console.log(e.isPrimary);   // true for the first touch in a multi-touch gesture

  // Capture the pointer so pointermove/up fire even outside the element
  canvas.setPointerCapture(e.pointerId);
});

canvas.addEventListener('pointermove', (e: PointerEvent) => {
  // Receives events even when pointer moves outside canvas (capture active)
});

canvas.addEventListener('pointerup', (e: PointerEvent) => {
  canvas.releasePointerCapture(e.pointerId);
});

const lazyImages = document.querySelectorAll<HTMLImageElement>('img[data-src]');

const observer = new IntersectionObserver((entries) => {
  for (const entry of entries) {
    if (entry.isIntersecting) {
      const img = entry.target as HTMLImageElement;
      img.src = img.dataset.src!; // load the real image
      observer.unobserve(img);    // stop watching once loaded
    }
  }
}, {
  rootMargin: '200px 0px', // start loading 200px before entering viewport
  threshold:  0.1,          // fire when 10% of the element is visible
});

lazyImages.forEach(img => observer.observe(img));

