import { ComponentFixture, TestBed } from '@angular/core/testing';
import { By } from '@angular/platform-browser';

describe('CounterComponent', () => {
  let fixture: ComponentFixture<CounterComponent>;
  let component: CounterComponent;

  beforeEach(async () => {
    await TestBed.configureTestingModule({
      imports: [CounterComponent],
    }).compileComponents();
    fixture   = TestBed.createComponent(CounterComponent);
    component = fixture.componentInstance;
    fixture.detectChanges();
  });

  it('increments on button click', () => {
    const btn = fixture.debugElement.query(By.css('.increment-btn'));
    btn.triggerEventHandler('click', new MouseEvent('click'));
    fixture.detectChanges();

    expect(component.count).toBe(1);
    expect(fixture.nativeElement.querySelector('.count').textContent).toBe('1');
  });

  it('calls preventDefault on form submit', () => {
    const form  = fixture.debugElement.query(By.css('form'));
    const event = new SubmitEvent('submit', { bubbles: true, cancelable: true });
    spyOn(event, 'preventDefault');
    form.nativeElement.dispatchEvent(event);

    expect(event.preventDefault).toHaveBeenCalled();
  });
});

// Pure unit test for an event handler helper (no TestBed needed)
describe('debounce()', () => {
  beforeEach(() => jasmine.clock().install());
  afterEach(()  => jasmine.clock().uninstall());

  it('delays execution', () => {
    const spy = jasmine.createSpy();
    const fn  = debounce(spy, 300);
    fn(); fn(); fn();         // call three times rapidly
    jasmine.clock().tick(299);
    expect(spy).not.toHaveBeenCalled();
    jasmine.clock().tick(1);
    expect(spy).toHaveBeenCalledTimes(1);
  });
});
